---common
function ModelAchievement:ParseConfig()
	self._achievementRewards= {}
	self._achievementLvlRewards= {}

	for k,v in pairs(GameTable.MissionAchiRef) do
		local reward = v.reward
		local rewardList = LxDataHelper.ParseItem(reward)
		self._achievementRewards[v.refId]= rewardList
	end

	for k,v in pairs(GameTable.MissionAchvLvRef) do
		local reward = v.reward
		local rewardList = LxDataHelper.ParseItem(reward)
		self._achievementLvlRewards[v.refId]= rewardList
	end
end

