---resp
function ModelAchievement:OnAchievementListResp(pb)
	self._achievementLvl = pb.lvl or 0
	self._achievementExp = pb.exp or 0
	self._achievementRank = pb.rank

	local isChangeList = false
	local haveHide		= false
	if pb.addList then
		isChangeList = true
		for k,v in ipairs(pb.addList) do
			if self:RefreshAchievementData(v) then
				haveHide = true
			end
		end
	end

	if pb.updateList then
		isChangeList = true
		for k,v in ipairs(pb.updateList) do
			if self:RefreshAchievementData(v) then
				haveHide = true
			end
		end
	end

	if isChangeList then
		FireEvent(EventNames.ON_ACHIEVEMENT_CHANGE)
	else
		FireEvent(EventNames.ON_ACHIEVEMENT_LVL_CHANGE)
	end

	if haveHide then
		self:ShowPopupHide()
	end

	gModelGeneral:CheckShowFinishTip()
end

function ModelAchievement:RefreshAchievementData(data)
	local haveHide = false
	local achievement = StructAchievement:New()
	achievement:CreateByPb(data)
	local refId = data.refId
	local cfg = self:GetAchievementConfig(refId)
	if cfg then
		achievement:SetType(cfg.type)
		achievement:SetSort(cfg.sort)
		achievement:SetHide(cfg.hide)
		achievement:SetProgressValue()

		local type = cfg.type
		local typeCfg = GameTable.MissionClassifyRef[type]
		local needTip = typeCfg and typeCfg.finishTips == 1

		if needTip then
			local oldData = self._achievementDataList[refId]
			if oldData then
				local oldState =  oldData:GetState()
				local newState = achievement:GetState()

				if oldState == 0 and newState == 1 then
					local title = string.replace(ccClientText(12216),ccLngText(typeCfg.title))
					local tipData =
					{
						title = title,
						desc = ccLngText(cfg.description),
						jumpId = typeCfg.functionOpenRefId,
					}
					--table.insert(self._finishTipList,tipData)
					gModelGeneral:AddShowFinishTips(tipData)
				end
			end
		end

		if achievement:GetPopup() == ModelAchievement.ACHIEVEMENT_HIDE_SHOW then
			self:SetPopupRefIdList(refId)
			haveHide = true
		end

		self._achievementDataList[refId]= achievement
	end
	return haveHide
end
