function ModelAchievement:GetAchievementTypeList()
	local t ={}

	local prio =
	{
		[ModelAchievement.ATHLETICS] = 1,
		[ModelAchievement.COMBAT] = 2,
		[ModelAchievement.SPECIAL] = 3
	}

	for k,v in pairs(GameTable.MissionClassifyRef) do
		local refId = v.refId
		local sortIndex = prio[refId]
		if sortIndex and v.frontEnd ==1 then
			local funcId = v.functionOpenRefId
			local isShow = gModelFunctionOpen:CheckIsShow(funcId)
			if isShow then
				t[refId] = refId
			end
		end
	end

	return t
end

function ModelAchievement:GetAchievementList(type, onlyComplete, jumpSort)
	local t = {}

	for k,v in pairs(self._achievementDataList) do
		local needAdd = false
		if type then
			if v:GetType() == type then
				needAdd = true
			end
		else
			--获取全部
			needAdd = true
		end

		if needAdd and (onlyComplete or v:GetHide()) then
			local state = v:GetState()
			needAdd = state ~= ModelAchievement.ACHIEVEMENT_UNFINISH
		end

		if needAdd then
			table.insert(t,v)
		end
	end

	if jumpSort then
		return t
	end

	table.sort(t,function(a,b)
		local aState = a:GetState()
		local aPrio = self:GetStatePrio(aState)
		local bState = b:GetState()
		local bPrio = self:GetStatePrio(bState)

		if aPrio~=bPrio then
			return aPrio<bPrio
		end

		--当前进度值
		if aState == ModelAchievement.ACHIEVEMENT_UNFINISH then
			local aProgressValue = tonumber(a:GetProgressValue())
			local bProgressValue = tonumber(b:GetProgressValue())
			if aProgressValue ~= bProgressValue then
				return aProgressValue > bProgressValue
			end
		end

		--完成日期
		local aDate = a:GetFinishTime()
		local bDate = b:GetFinishTime()
		if aDate ~= bDate then
			return aDate > bDate
		end

		return a:GetSort() < b:GetSort()
	end)
	return t
end

function ModelAchievement:GetStatePrio(state)
	if state == ModelAchievement.ACHIEVEMENT_UNFINISH then
		return 1
	elseif state == ModelAchievement.ACHIEVEMENT_FINNISH then
		return 0
	else
		return 2
	end
end

function ModelAchievement:GetAchievementConfig(refId)
	local cfg = GameTable.MissionAchiRef[refId]
	if not cfg then
		printInfoNR("no cfg GameTable.MissionAchiRef refId = "..(refId or "nil"))
	end
	return cfg
end

function ModelAchievement:GetAchievementName(refId)
    local cfg = self:GetAchievementConfig(refId)
    if not cfg then
        return ""
    end

    return ccLngText(cfg.name)
end

function ModelAchievement:GetAchievementDescription(refId)
	local cfg = self:GetAchievementConfig(refId)
	if not cfg then
		return ""
	end

	return ccLngText(cfg.description)
end

