function ModelAchievement:GetAchievementLvlCfgByLvl(lvl)
	for k,v in pairs(GameTable.MissionAchvLvRef) do
		if v.refId == lvl then
			return v
		end
	end

	return nil
end

function ModelAchievement:GetAchievementLvlCfgList()
	local cfgList = {}
	for i = 1, 999 do
		local cfg = GameTable.MissionAchvLvRef[i]
		if cfg then
			table.insert(cfgList, cfg)
		else
			return cfgList
		end
	end

	return cfgList
end

function ModelAchievement:GetCurAchievementRank()
	return self._achievementRank
end

function ModelAchievement:SetPopupRefIdList(refId)
	for k,v in ipairs(self._popupRefIdList) do
		if v == refId then
			return
		end
	end

	table.insert(self._popupRefIdList, refId)
end

function ModelAchievement:GetNextPopupRefId()
	return table.remove(self._popupRefIdList, 1)
end

function ModelAchievement:CheckHavePopup()
	local popupNum = #self._popupRefIdList
	return popupNum > 0
end

function ModelAchievement:GetShowType()
	local defaultType = ModelAchievement.ALL
	return defaultType
end

function ModelAchievement:GetNeedWaitPopList()
	return self._wndStr
end

