---隐藏成就弹窗
function ModelAchievement:ShowPopupHide()
	if GF.FindFirstWndByName("UIFeatHide")then
		return
	end

	if not self:CheckHavePopup() then
		return
	end

	local hasEnterMain = gModelGeneral:GetHasEnteredCityMap()
	if not hasEnterMain then
		return
	end

	local isInGuide = gModelGuide:IsInGuide()
	if isInGuide then
		return
	end

	local isInPlot = gModelPlot:IsInPlot()
	if isInPlot then
		return
	end

	local inBattle  = gModelBattle:ExistPositiveBattle()
	if inBattle then
		return
	end

	local needWait = self:CheckNeedWaitShowPopupHide()
	if needWait then
		--gModelGeneral:InsertPopAchievementHideWnd()
		return
	else
		GF.OpenWndUp("UIFeatHide")
	end
end

function ModelAchievement:CheckNeedWaitShowPopupHide()
	if not gModelGeneral:GetHasEnteredCityMap() then
		return true
	end

	if gModelGuide:IsInGuide() then
		return true
	end

	local needWait = false
	for k, v in ipairs(self._wndStr) do
		if(GF.FindFirstWndByName(v))then
			needWait = true
			break
		end
	end

	return needWait
end

