function ModelAchievement:CheckShowAchievementMainRed()
	for k,v in ipairs(self._childTypes) do
		if self:IsHaveAchievementFinished(v) then
			return true
		end
	end
	return false
end

function ModelAchievement:IsHaveAchievementFinished(achievementType)
	local showRedState = ModelAchievement.ACHIEVEMENT_FINNISH
	for k,v in pairs(self._achievementDataList) do
		if (not achievementType or v:GetType() == achievementType) and
				v:GetState() == showRedState then
			return true
		end
	end
	return false
end

function ModelAchievement:CheckShowAchievementChildPageRed(achievementType)
	return self:IsHaveAchievementFinished(achievementType)
end
